import React, { useState } from 'react';
import { submitPhysical } from '../services/api';

const SubmitToPoliceButton = ({ itemId, onSubmitted }) => {
    const [loading, setLoading] = useState(false);

    const handleClick = async () => {
        const police_station = prompt('Enter police station/location where you will submit the item:');
        if (!police_station) return;
        const location_details = prompt('Optional: any location details (desk, receipt ref)');
        setLoading(true);
        try {
            await submitPhysical(itemId, { police_station, location_details });
            alert('Submission created and is pending police verification.');
            if (onSubmitted) onSubmitted();
        } catch (err) {
            console.error(err);
            alert(err.response?.data?.message || 'Submission failed.');
        } finally { setLoading(false); }
    };

    return (
        <button className="btn btn-warning" onClick={handleClick} disabled={loading}>
            {loading ? 'Submitting...' : 'Submit to Police'}
        </button>
    );
};

export default SubmitToPoliceButton;
